def parser(log: str) -> dict[str, str]:
    import re
    from json import JSONDecoder

    results: dict[str, str] = {}
    status_rank = {"pass": 0, "skip": 1, "fail": 2}

    def normalize_status(raw):
        if raw is None:
            return None
        s = str(raw).strip().lower()
        if s in {"passed", "pass", "success", "ok"}:
            return "pass"
        if s in {"failed", "fail", "error", "errors", "failure", "broken"}:
            return "fail"
        if s in {"skipped", "skip", "pending", "todo", "disabled", "ignored", "xfailed", "xfail"}:
            return "skip"
        if s in {"xpassed", "xpass"}:
            return "fail"
        return None

    def add_result(name, status):
        if not name or not status:
            return
        prev = results.get(name)
        if prev is None or status_rank[status] > status_rank[prev]:
            results[name] = status

    def build_name(ancestors, title):
        parts = [p for p in (ancestors or []) if p]
        if title:
            parts.append(title)
        return " ".join(parts).strip()

    def handle_assertion(assertion):
        if not isinstance(assertion, dict):
            return
        name = assertion.get("fullName")
        if not name:
            name = build_name(assertion.get("ancestorTitles"), assertion.get("title"))
        status = normalize_status(assertion.get("status"))
        add_result(name, status)

    def handle_task(task):
        if not isinstance(task, dict):
            return
        task_type = task.get("type")
        name = task.get("fullName") or task.get("name") or task.get("title")
        status = normalize_status(task.get("status"))
        result = task.get("result") or {}
        status = status or normalize_status(result.get("state")) or normalize_status(result.get("status"))
        if task_type in {"test", "case"}:
            add_result(name, status)
        for key in ("tasks", "children"):
            children = task.get(key)
            if isinstance(children, list):
                for child in children:
                    handle_task(child)

    def walk(obj):
        if isinstance(obj, dict):
            if isinstance(obj.get("assertionResults"), list):
                for assertion in obj.get("assertionResults"):
                    handle_assertion(assertion)
            if isinstance(obj.get("testResults"), list):
                for suite in obj.get("testResults"):
                    walk(suite)
            if isinstance(obj.get("tasks"), list):
                for task in obj.get("tasks"):
                    handle_task(task)

            name = obj.get("fullName") or obj.get("name") or obj.get("title")
            status = normalize_status(obj.get("status"))
            container_keys = {"assertionResults", "testResults", "children", "tasks", "suites", "tests"}
            if name and status and not any(k in obj for k in container_keys):
                add_result(name, status)

            for value in obj.values():
                walk(value)
        elif isinstance(obj, list):
            for item in obj:
                walk(item)

    decoder = JSONDecoder()
    idx = 0
    while idx < len(log):
        match = re.search(r"[\{\[]", log[idx:])
        if not match:
            break
        start = idx + match.start()
        try:
            data, end = decoder.raw_decode(log, start)
        except Exception:
            idx = start + 1
            continue
        walk(data)
        idx = end

    if "<testcase" in log:
        testcase_pattern = re.compile(
            r"<testcase\b([^>]*)>(.*?)</testcase>|<testcase\b([^>]*)/>",
            re.DOTALL | re.IGNORECASE,
        )
        for m in testcase_pattern.finditer(log):
            attrs = m.group(1) or m.group(3) or ""
            body = m.group(2) or ""
            name_match = re.search(r'name="([^"]+)"', attrs)
            class_match = re.search(r'classname="([^"]+)"', attrs)
            if not name_match:
                continue
            name = name_match.group(1)
            classname = class_match.group(1) if class_match else ""
            full = f"{classname}.{name}" if classname else name
            status = "pass"
            if re.search(r"<failure\b|<error\b", body, re.IGNORECASE):
                status = "fail"
            elif re.search(r"<skipped\b", body, re.IGNORECASE):
                status = "skip"
            add_result(full, status)

    for line in log.splitlines():
        line = line.rstrip()

        m = re.match(r"^(\S+::\S+)\s+(PASSED|FAILED|SKIPPED|XFAILED|XPASSED|ERROR)\b", line)
        if m:
            add_result(m.group(1), normalize_status(m.group(2)))
            continue

        m = re.match(r"^(\w+(?:\.\w+)+)\s+\.\.\.\s+(ok|FAIL|ERROR|skipped)\b", line, re.IGNORECASE)
        if m:
            add_result(m.group(1), normalize_status(m.group(2)))
            continue

        m = re.match(r"^---\s+(PASS|FAIL|SKIP):\s+(\S+)", line)
        if m:
            add_result(m.group(2), normalize_status(m.group(1)))
            continue

        m = re.match(r"^\s*([✓✕○])\s+(.+)$", line)
        if m:
            symbol = m.group(1)
            status = {"✓": "pass", "✕": "fail", "○": "skip"}.get(symbol)
            add_result(m.group(2).strip(), status)
            continue

        m = re.match(r"^(ok|not ok)\s+\d+\s+-\s+(.+)$", line, re.IGNORECASE)
        if m:
            status = "pass" if m.group(1).lower() == "ok" else "fail"
            add_result(m.group(2).strip(), status)
            continue

    return results
